sys_variable_value.value:
(function execute(inputs, outputs) {
    var importHelper = new global.workspaceImportOnDemand();
    var result = importHelper.importAndTransform(
        inputs.dataSourceSysId,
        inputs.transformMapSysId
    );
    outputs.import_set_sys_id = result ? result.import_set_sys_id : '';
})(inputs, outputs);

